// Helper: get recipes by filters
export function getRecipes(mealType, cuisine, tags) {
    return RECIPE_BANK.filter(r => {
        const matchesMeal = r.mealType.includes(mealType);
        const matchesCuisine = !cuisine || r.cuisine === cuisine;
        const matchesTags = !tags || tags.some(t => r.tags.includes(t));
        return matchesMeal && matchesCuisine && matchesTags;
    });
}
export function getRecipeById(id) {
    return RECIPE_BANK.find(r => r.id === id);
}
export function getAlternatives(current, count = 3) {
    return RECIPE_BANK
        .filter(r => r.id !== current.id &&
        r.mealType.some(m => current.mealType.includes(m)))
        .sort(() => Math.random() - 0.5)
        .slice(0, count);
}
